/////////////////////////\n// PROJECTS\n//////////////////////////////////////////////////////\n\nmodel Project {\n  id          String        @id @default(cuid())\n  name        String\n  description String?\n  status      ProjectStatus @default(DRAFT)\n  budget      Float?\n  client_id   String\n  manager_id  String\n  start_date  DateTime?\n  end_date    DateTime?\n  created_at  DateTime      @default(now())\n  updated_at  DateTime      @updatedAt\n\n  client  User @relation(\"ProjectClient\", fields: [client_id], references: [id])\n  manager User @relation(\"ProjectManager\", fields: [manager_id], references: [id])\n\n  team_members   TeamMember[]\n  tasks          Task[]\n  invoices       Invoice[]\n  communications Communication[]\n  ai_analyses    AIAnalysis[]\n\n  @@map(\"projects\")\n}\n\n//////////////////////////////////////////////////////\n// TEAM MEMBERS\n//////////////////////////////////////////////////////\n\nmodel TeamMember {\n  id         String   @id @default(cuid())\n  project_id String\n  user_id    String\n  role       String\n  joined_at  DateTime @default(now())\n\n  project Project @relation(fields: [project_id], references: [id], onDelete: Cascade)\n  user    User    @relation(fields: [user_id], references: [id], onDelete: Cascade)\n\n  @@unique([project_id, user_id])\n  @@map(\"team_members\")\n}\n\n//////////////////////////////////////////////////////\n// TASKS\n//////////////////////////////////////////////////////\n\nmodel Task {\n  id          String       @id @default(cuid())\n  project_id  String\n  assigned_to String?\n  title       String\n  description String?\n  status      TaskStatus   @default(TODO)\n  priority    TaskPriority @default(MEDIUM)\n  due_date    DateTime?\n  created_at  DateTime     @default(now())\n  updated_at  DateTime     @updatedAt\n\n  project  Project @relation(fields: [project_id], references: [id], onDelete: Cascade)\n  assignee User?   @relation(fields: [assigned_to], references: [id])\n\n  ai_analyses AIAnalysis[]\n\n  @@map(\"tasks\")\n}\n\n//////////////////////////////////////////////////////\n// INVOICES\n//////////////////////////////////////////////////////\n\nmodel Invoice {\n  id         String        @id @default(cuid())\n  project_id String\n  client_id  String\n  amount     Float\n  due_date   DateTime\n  status     InvoiceStatus @default(PENDING)\n  created_at DateTime      @default(now())\n  updated_at DateTime      @updatedAt\n\n  project Project @relation(fields: [project_id], references: [id], onDelete: Cascade)\n  client  User    @relation(fields: [client_id], references: [id], onDelete: Cascade)\n\n  payments Payment[]\n\n  @@map(\"invoices\")\n}\n\n//////////////////////////////////////////////////////\n// PAYMENTS\n//////////////////////////////////////////////////////\n\nmodel Payment {\n  id         String        @id @default(cuid())\n  invoice_id String\n  amount     Float\n  method     PaymentMethod\n  status     PaymentStatus @default(COMPLETED)\n  paid_at    DateTime      @default(now())\n  created_at DateTime      @default(now())\n\n  invoice Invoice @relation(fields: [invoice_id], references: [id], onDelete: Cascade)\n\n  @@map(\"payments\")\n}\n\n//////////////////////////////////////////////////////\n// COMMUNICATIONS\n//////////////////////////////////////////////////////\n\nmodel Communication {\n  id          String              @id @default(cuid())\n  project_id  String?\n  sender_id   String?\n  receiver_id String?\n  subject     String?\n  body        String\n  file_url    String?\n  type        CommunicationType   @default(MESSAGE)\n  status      CommunicationStatus @default(UNREAD)\n  created_at  DateTime            @default(now())\n\n  project Project? @relation(fields: [project_id], references: [id], onDelete: Cascade)\n\n  sender   User? @relation(\"CommunicationSender\", fields: [sender_id], references: [id])\n  receiver User? @relation(\"CommunicationReceiver\", fields: [receiver_id], references: [id])\n\n  ai_analyses AIAnalysis[]\n\n  @@map(\"communications\")\n}\n\n//////////////////////////////////////////////////////\n// AI ANALYSIS\n//////////////////////////////////////////////////////\n\nmodel AIAnalysis {\n  id               String  @id @default(cuid())\n  project_id       String?\n  task_id          String?\n  communication_id String?\n  user_id          String?\n\n  analysis_type AIAnalysisType\n  result        String\n  confidence    Float?\n  metadata      Json?\n\n  created_at DateTime @default(now())\n\n  project       Project?       @relation(fields: [project_id], references: [id], onDelete: Cascade)\n  task          Task?          @relation(fields: [task_id], references: [id], onDelete: Cascade)\n  communication Communication? @relation(fields: [communication_id], references: [id], onDelete: Cascade)\n  user          User?          @relation(fields: [user_id], references: [id], onDelete: Cascade)\n\n  @@map(\"ai_analyses\")\n}\n\n//////////////////////////////////////////////////////\n// REFRESH TOKENS\n//////////////////////////////////////////////////////\n\nmodel RefreshToken {\n  id         String   @id @default(cuid())\n  user_id    String\n  token      String   @db.Text\n  expires_at DateTime\n  created_at DateTime @default(now())\n\n  user User @relation(fields: [user_id], references: [id], onDelete: Cascade)\n\n  @@map(\"refresh_tokens\")\n}\n",
